  await browser.open(`${params.listing_url}`)

  // Wait for listing page to load
  await browser.waitForSelector('.x-item-title__mainTitle, h1.it-ttl, h1[class*=\'title\'], .vim.x-item-title', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load additional content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

